import 'package:drift/drift.dart';
import 'package:drift_flutter/drift_flutter.dart';
import 'package:flutter/foundation.dart';
import 'package:logging/logging.dart';

// Import tables
import 'tables.dart';
import 'daos/card_dao.dart';
import 'daos/search_dao.dart';

// Generated by drift_dev when running `dart run build_runner build`
part 'app_database.g.dart';

@DriftDatabase(
  tables: [
    Tasks,
    AgentRuns,
    KvStore,
    AgentActivityMessages,
    CardCache,
    SystemActions,
    ClarificationRequests,
    PersonaChatMessages,
    UserNotifications,
  ],
  daos: [CardDao],
)
class AppDatabase extends _$AppDatabase {
  final Logger _logger = Logger('AppDatabase');

  /// Lazy-initialized SearchDao for FTS5 full-text search.
  late final SearchDao searchDao = SearchDao(this);

  /// Set to true during onUpgrade when FTS tables are first created for an
  /// existing user. [MemexRouter._init] reads and clears this after services
  /// are ready so it can trigger a one-time full rebuild.
  bool _needsFtsRebuild = false;

  /// Whether a full FTS rebuild is needed (set during migration, cleared after rebuild).
  bool get needsFtsRebuild => _needsFtsRebuild;

  /// Clear the FTS rebuild flag after the rebuild has been triggered.
  void clearFtsRebuildFlag() => _needsFtsRebuild = false;

  /// Singleton pattern to ensure one DB connection
  static AppDatabase?
      _instance; // We will treat the current opened DB as singleton for the app lifecycle
  static AppDatabase get instance {
    if (_instance == null) {
      throw Exception(
          'Database not initialized. Call AppDatabase.init(userId) first.');
    }
    return _instance!;
  }

  static bool get isInitialized => _instance != null;

  /// Initialize the database for a specific user
  static Future<void> init(String userId) async {
    if (_instance != null) {
      await _instance!.close();
      _instance = null;
    }

    _instance = AppDatabase._(userId);
  }

  /// Private constructor
  AppDatabase._(String userId) : super(_openConnection(userId));

  @visibleForTesting
  static void setTestInstance(AppDatabase database) {
    _instance = database;
  }

  @visibleForTesting
  AppDatabase.forTesting(super.executor);

  @override
  int get schemaVersion => 15;

  @override
  MigrationStrategy get migration => MigrationStrategy(
        onCreate: (Migrator m) async {
          await m.createAll();
          // Create indices
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_tasks_status ON tasks(status)');
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_tasks_scheduled_at ON tasks(scheduled_at)');
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_tasks_type_biz_id ON tasks(type, biz_id)');
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_tasks_run_id ON tasks(run_id)');
          await _createAgentRunIndices();
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_kv_bucket ON kv_store(bucket)');
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_card_cache_timestamp ON card_cache(timestamp)');
          await customStatement(
              'CREATE INDEX IF NOT EXISTS idx_system_actions_status ON system_actions(status)');
          await _createClarificationRequestIndices();
          await _createUserNotificationIndices();
          // Create FTS5 virtual tables for full-text search
          await searchDao.createFtsTables();
        },
        onUpgrade: (Migrator m, int from, int to) async {
          if (from < 2) {
            await m.createTable(agentActivityMessages);
          }
          // Only add agent_id column if upgrading from version 2 to 3
          // If upgrading from version 1, the table was just created with all columns including agent_id
          if (from == 2 && to >= 3) {
            // Try to add the column, but ignore if it already exists
            try {
              await m.addColumn(
                  agentActivityMessages, agentActivityMessages.agentId);
            } catch (e) {
              // If column already exists (duplicate column error), ignore it
              final errorStr = e.toString().toLowerCase();
              if (errorStr.contains('duplicate column') ||
                  (errorStr.contains('sqlite') &&
                      errorStr.contains('agent_id'))) {
                _logger
                    .info('agent_id column already exists, skipping migration');
              } else {
                // Re-throw if it's a different error
                rethrow;
              }
            }
          }
          if (from < 4) {
            try {
              await m.addColumn(tasks, tasks.dependencies);
            } catch (e) {
              _logger.info(
                  'dependencies column might already exist, skipping: $e');
            }
          }
          if (from < 5) {
            await m.createTable(cardCache);
            await customStatement(
                'CREATE INDEX IF NOT EXISTS idx_card_cache_timestamp ON card_cache(timestamp)');
          }
          if (from < 7) {
            await m.createTable(systemActions);
            await customStatement(
                'CREATE INDEX IF NOT EXISTS idx_system_actions_status ON system_actions(status)');
          }
          if (from < 8) {
            try {
              await customStatement(
                  'ALTER TABLE card_cache DROP COLUMN is_draft');
            } catch (e) {
              _logger
                  .info('is_draft column may not exist or already dropped: $e');
            }
          }
          if (from < 9) {
            await m.createTable(personaChatMessages);
            await customStatement(
                'CREATE INDEX IF NOT EXISTS idx_persona_chat_character ON persona_chat_messages(character_id)');
            await customStatement(
                'CREATE INDEX IF NOT EXISTS idx_persona_chat_unread ON persona_chat_messages(character_id, is_read)');
          }
          if (from < 10) {
            // Create FTS5 virtual tables for full-text search.
            // Existing users upgrading to v10 need a full FTS rebuild
            // because their data was never indexed. We set a flag here
            // and MemexRouter._init() picks it up after all services are ready.
            await searchDao.createFtsTables();
            _needsFtsRebuild = true;
          }
          if (from < 11) {
            await _createClarificationRequestsTable(m);
          }
          if (from < 12) {
            await m.createTable(userNotifications);
            await _createUserNotificationIndices();
          }
          if (from < 13) {
            // Create FTS5 virtual tables for character world and timeline search.
            await searchDao.createCharacterFtsTables();
          }
          if (from < 14) {
            // Add messageType column to persona_chat_messages.
            try {
              await customStatement(
                  "ALTER TABLE persona_chat_messages ADD COLUMN message_type TEXT NOT NULL DEFAULT 'chat'");
            } catch (e) {
              _logger
                  .info('message_type column may already exist, skipping: $e');
            }
          }
          if (from < 15) {
            await _addTaskRunIdColumn(m);
            await _createAgentRunsTable(m);
          }
        },
      );

  Future<void> _addTaskRunIdColumn(Migrator m) async {
    try {
      await m.addColumn(tasks, tasks.runId);
    } catch (e) {
      final errorStr = e.toString().toLowerCase();
      if (errorStr.contains('duplicate column') ||
          (errorStr.contains('sqlite') && errorStr.contains('run_id'))) {
        _logger.info('run_id column already exists on tasks, skipping');
      } else {
        rethrow;
      }
    }
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_tasks_run_id ON tasks(run_id)');
  }

  Future<void> _createAgentRunsTable(Migrator m) async {
    try {
      await m.createTable(agentRuns);
    } catch (e) {
      if (_isAlreadyExistsError(e, 'agent_runs')) {
        _logger.info('agent_runs table already exists, skipping migration');
      } else {
        rethrow;
      }
    }
    await _createAgentRunIndices();
  }

  Future<void> _createAgentRunIndices() async {
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_agent_runs_user_state_updated '
        'ON agent_runs(user_id, state, updated_at)');
    await customStatement('CREATE INDEX IF NOT EXISTS idx_agent_runs_fact_id '
        'ON agent_runs(fact_id)');
  }

  Future<void> _createClarificationRequestsTable(Migrator m) async {
    try {
      await m.createTable(clarificationRequests);
    } catch (e) {
      if (_isAlreadyExistsError(e, 'clarification_requests')) {
        _logger.info(
            'clarification_requests table already exists, skipping migration');
      } else {
        rethrow;
      }
    }
    await _createClarificationRequestIndices();
  }

  Future<void> _createClarificationRequestIndices() async {
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_clarification_requests_status ON clarification_requests(status)');
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_clarification_requests_fact_id ON clarification_requests(fact_id)');
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_clarification_requests_dedupe ON clarification_requests(dedupe_key)');
  }

  Future<void> _createUserNotificationIndices() async {
    await customStatement(
        'CREATE UNIQUE INDEX IF NOT EXISTS idx_user_notifications_unique '
        'ON user_notifications(user_id, notification_type, subject_key)');
    await customStatement(
        'CREATE INDEX IF NOT EXISTS idx_user_notifications_list '
        'ON user_notifications(user_id, notification_type, updated_at)');
  }

  bool _isAlreadyExistsError(Object error, String tableName) {
    final errorStr = error.toString().toLowerCase();
    return errorStr.contains(tableName) &&
        (errorStr.contains('already exists') ||
            errorStr.contains('duplicate table'));
  }
}

/// Opens the connection using drift_flutter
QueryExecutor _openConnection(String userId) {
  final dbName = 'memex_local_$userId';

  return driftDatabase(name: dbName);
}
